    41	    fn match_to_lint(&self, matched_tokens: &[Token], source: &[char]) -> Option<Lint> {
    42	        let word = &matched_tokens[0];
    43	
    44	        // If it's a recognized word, we don't care about it.
    45	        if word.kind.as_word().unwrap().is_some() {
    46	            return None;
    47	        }
    48	
    49	        let chars = &word.get_ch(source);
    50	
    51	        // Get all possible prefix candidates from trie and extract valid split positions
    52	        let candidates = self.dict.find_words_with_common_prefix(chars);
    53	        let len = chars.len();
    54	        let mut valid_positions: HashSet<usize> = HashSet::new();
    55	
    56	        for candidate in candidates {
    57	            if candidate.len() >= len {
    58	                continue;
    59	            }
    60	            valid_positions.insert(candidate.len());
    61	        }
    62	
    63	        // Generate middle-outward position order based on heuristic from PR #885:
    64	        // Missing spaces are more likely near the middle of a word
    65	        let mid = len / 2;
    66	        let mut positions: Vec<usize> = Vec::new();
    67	        positions.push(mid);
    68	
    69	        for offset in 1..len {
    70	            if mid >= offset {
    71	                positions.push(mid - offset);
    72	            }
    73	            if mid + offset < len {
    74	                positions.push(mid + offset);
    75	            }
    76	        }
    77	
    78	        let mut suggestions = Vec::new();
    79	        let mut message: Option<String> = None;
    80	
    81	        // Check positions in middle-outward order
    82	        for split_pos in positions {
    83	            if split_pos == 0 || split_pos >= len || !valid_positions.contains(&split_pos) {
    84	                continue;
    85	            }
    86	
    87	            let candidate = &chars[..split_pos];
    88	            let remainder = &chars[split_pos..];
    89	
    90	            // Both parts must be valid common words
    91	            if let Some(cand_meta) = self.dict.get_word_metadata(candidate) {
    92	                if !cand_meta.common {
    93	                    continue;
    94	                }
    95	            } else {
    96	                continue;
    97	            }
    98	
    99	            if let Some(rem_meta) = self.dict.get_word_metadata(remainder) {
   100	                if !rem_meta.common {
   101	                    continue;
   102	                }
   103	            } else {
   104	                continue;
   105	            }
   106	
   107	            // Valid split found
   108	            let mut suggestion = Vec::new();
   109	            suggestion.extend(candidate.iter());
   110	            suggestion.push(' ');
   111	            suggestion.extend(remainder.iter());
   112	
   113	            suggestions.push(Suggestion::ReplaceWith(suggestion));
   114	            if suggestions.len() == 1 {
   115	                message = Some(format!(
   116	                    "`{}` should probably be written as `{} {}`.",
   117	                    chars.iter().collect::<String>(),
   118	                    candidate.iter().collect::<String>(),
   119	                    remainder.iter().collect::<String>()
   120	                ));
   121	            }
   122	        }
   123	
   124	        if !suggestions.is_empty() {
   125	            let original_word: String = chars.iter().collect();
   126	
   127	            if suggestions.len() != 1 {
   128	                message = Some(format!(
   129	                    "`{original_word}` has a missing space between words."
   130	                ));
   131	            }
   132	
   133	            return Some(Lint {
   134	                span: word.span,
   135	                lint_kind: LintKind::Typo,
   136	                suggestions,
   137	                message: message?,
   138	                priority: 31,
   139	            });
   140	        }
   141	
   142	        None
   143	    }
   144	}
