   298	            config: FlatConfig::default(),
   299	            linters: BTreeMap::new(),
   300	            chunk_expr_linters: BTreeMap::new(),
   301	            chunk_expr_cache: LruCache::new(NonZero::new(1000).unwrap()),
   302	            hasher_builder: RandomState::default(),
