   543	    pub fn organized_lints(&mut self, document: &Document) -> BTreeMap<String, Vec<Lint>> {
   544	        let mut results = BTreeMap::new();
   545	
   546	        // Normal linters
   547	        for (key, linter) in &mut self.linters {
   548	            if self.config.is_rule_enabled(key) {
   549	                results.insert(key.to_owned(), linter.lint(document));
   550	            }
   551	        }
   552	
   553	        // Expr linters
   554	        for chunk in document.iter_chunks() {
   555	            let Some(chunk_span) = chunk.span() else {
   556	                continue;
   557	            };
   558	
   559	            let chunk_chars = document.get_span_content(&chunk_span);
   560	            let config_hash = self.hasher_builder.hash_one(&self.config);
   561	            let char_hash = self.hasher_builder.hash_one(chunk_chars);
   562	            let cache_key = (char_hash, config_hash);
   563	
   564	            let chunk_results = if let Some(hit) = self.chunk_expr_cache.get(&cache_key) {
   565	                hit.clone()
   566	            } else {
   567	                let mut pattern_lints = BTreeMap::new();
   568	
   569	                for (key, linter) in &mut self.chunk_expr_linters {
   570	                    if self.config.is_rule_enabled(key) {
   571	                        let lints =
   572	                            run_on_chunk(linter, chunk, document.get_source()).map(|mut l| {
   573	                                l.span.pull_by(chunk_span.start);
   574	                                l
   575	                            });
   576	
   577	                        pattern_lints.insert(key.clone(), lints.collect());
   578	                    }
   579	                }
   580	
   581	                let pattern_lints = Lrc::new(pattern_lints);
   582	
   583	                self.chunk_expr_cache.put(cache_key, pattern_lints.clone());
   584	                pattern_lints
   585	            };
   586	
   587	            for (key, vec) in chunk_results.iter() {
   588	                results
   589	                    .entry(key.to_owned())
   590	                    .or_default()
   591	                    .extend(vec.iter().cloned().map(|mut lint| {
   592	                        // Bring the spans back into document-space
   593	                        lint.span.push_by(chunk_span.start);
   594	                        lint
   595	                    }));
   596	            }
   597	        }
   598	
   599	        results
   600	    }
   601	}
